import mongoose, { Document, Schema } from 'mongoose'

export enum Category {
  AI = 'AI',
  CTDL = 'CTDL',
  WEB_DEV = 'WEB_DEV',
  DEVOPS = 'DEVOPS',
  MOBILE = 'MOBILE',
}

export interface IArticle extends Document {
  _id: mongoose.Types.ObjectId
  slug: string
  title: string
  excerpt: string
  content: string
  category: Category
  tags: string[]
  authorId: mongoose.Types.ObjectId
  coverImage?: string
  readingTime: number
  published: boolean
  publishedAt?: Date
  createdAt: Date
  updatedAt: Date
}

const articleSchema = new Schema<IArticle>(
